    49→            <li
    50→              className="bg-white/10 border border-white/20 rounded-lg p-3 backdrop-blur-sm shadow-md"
    51→              key={t.id}
    52→            >
    53→              <span className="text-lg text-white">{t.name}</span>
    54→            </li>
    55→          ))}
    56→        </ul>
    57→        <div className="flex flex-col gap-2">
    58→          <input
    59→            className="w-full px-4 py-3 rounded-lg border border-white/20 bg-white/10 backdrop-blur-sm text-white placeholder-white/60 focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-transparent"
    60→            onChange={(e) => setTodo(e.target.value)}
    61→            onKeyDown={(e) => {
    62→              if (e.key === "Enter") {
    63→                submitTodo();
    64→              }
    65→            }}
    66→            placeholder="Enter a new todo..."
    67→            type="text"
    68→            value={todo}
    69→          />
    70→          <button
    71→            className="bg-blue-500 hover:bg-blue-600 disabled:bg-blue-500/50 disabled:cursor-not-allowed text-white font-bold py-3 px-4 rounded-lg transition-colors"
    72→            disabled={todo.trim().length === 0}
    73→            onClick={submitTodo}
    74→            type="button"
    75→          >
    76→            Add todo
    77→          </button>
    78→        </div>
    79→      </div>
    80→    </div>
    81→  );
    82→}
