     1→import { queryOptions, type UseQueryOptions } from "@tanstack/react-query";
     2→import { getApiClient } from "../apiClientInstance";
     3→import type { ApiClientError, ApiNamespace } from "../types/client";
     4→import type { GeneratedQueryKey } from "../types/query";
     5→import type { Params } from "../utils/cleanParams";
     6→import { makeSearchParams } from "../utils/makeSearchParams";
     7→
     8→export type UseGetOneOptions<TQueryFnData> = Omit<
     9→  UseQueryOptions<
    10→    TQueryFnData,
    11→    ApiClientError,
    12→    TQueryFnData,
    13→    GeneratedQueryKey
    14→  >,
    15→  "queryFn" | "queryKey"
    16→> & {
    17→  namespace?: ApiNamespace;
    18→  performRedirect?: boolean;
    19→  resourceKey?: string;
    20→};
    21→
    22→export const useGetOneQueryOptions = <DataShape>(
    23→  path: string,
    24→  params: Params,
    25→  queryKey: GeneratedQueryKey,
    26→  options: Partial<UseGetOneOptions<DataShape>> = {},
    27→) => {
    28→  const { namespace = "org", performRedirect, ...useQueryOptions } = options;
    29→
    30→  const queryParams = makeSearchParams(params);
    31→
    32→  const hydratedPath = `${path}?${queryParams.toString()}`;
    33→
    34→  return queryOptions({
    35→    queryFn: () =>
    36→      getApiClient(performRedirect, namespace).get<DataShape>(
    37→        hydratedPath,
    38→        undefined,
    39→      ),
    40→    queryKey,
    41→    ...useQueryOptions,
    42→  });
    43→};
    44→

