     1→import type { QueryKeyParams } from "../types/query";
     2→import { isTruthy } from "../utils/isTruthy";
     3→import { removeEmpty } from "../utils/removeEmpty";
     4→
     5→type KeyElement =
     6→  | Record<string, Record<string, string> | string | null | undefined>
     7→  | string;
     8→
     9→export type GeneratedQueryKey = readonly KeyElement[];
    10→
    11→export const generateQueryKey = ({
    12→  accountId,
    13→  namespace = "org",
    14→  parameters,
    15→  resourceId,
    16→  resourceKey,
    17→  resourceType,
    18→}: QueryKeyParams) => {
    19→  return [
    20→    namespace,
    21→    ...(accountId ? ["accounts", accountId] : []),
    22→    resourceKey,
    23→    resourceId,
    24→    resourceType,
    25→    removeEmpty(parameters),
    26→  ].filter(isTruthy);
    27→};
    28→
    29→/**
    30→ * Creates a resource keys object that can be used to generate query keys for a resource.
    31→ * Automatically adds the resource type (entity or list) to the resulting query key.
    32→ * @param keyGenerators - The key generators for the resource.
    33→ * @returns A resource keys object.
    34→ *
    35→ * @example
    36→ * ```ts
    37→ * const resourceKeys = createResourceKeys({
    38→ *   entity: (params) => ({
    39→ *     queryKey: generateQueryKey({ ...params, resourceKey: userResourceKeys.entity }),
    40→ *   }),
    41→ *   list: (params) => ({
    42→ *     queryKey: generateQueryKey({ ...params, resourceKey: userResourceKeys.list }),
    43→ *   }),
    44→ * });
    45→ * ```
    46→ */
    47→
    48→type ResourceKeyGenerators = {
    49→  entity?: (
    50→    params: Omit<QueryKeyParams, "resourceType"> & { resourceType: "entity" },
    51→  ) => {
    52→    queryKey: GeneratedQueryKey;
    53→  };
    54→  list?: (
    55→    params: Omit<QueryKeyParams, "resourceType"> & { resourceType: "list" },
    56→  ) => {
    57→    queryKey: GeneratedQueryKey;
    58→  };
    59→};
    60→
    61→// Return type will only include the keys that were provided
    62→type ResourceKeys<T extends ResourceKeyGenerators> = {
    63→  [K in keyof T as T[K] extends undefined ? never : K]: (
    64→    params: Omit<QueryKeyParams, "resourceType">,
    65→  ) => { queryKey: GeneratedQueryKey };
    66→};
    67→
    68→export const createResourceKeys = <T extends ResourceKeyGenerators>(
    69→  resourceKey: string,
    70→  keyGenerators: T,
    71→): ResourceKeys<T> => {
    72→  return {
    73→    ...(keyGenerators.entity
    74→      ? {
    75→          entity: (params: Omit<QueryKeyParams, "resourceType">) =>
    76→            keyGenerators.entity?.({
    77→              ...params,
    78→              resourceKey: params.resourceKey ?? resourceKey,
    79→              resourceType: "entity",
    80→            }),
    81→        }
    82→      : {}),
    83→    ...(keyGenerators.list
    84→      ? {
    85→          list: (params: Omit<QueryKeyParams, "resourceType">) =>
    86→            keyGenerators.list?.({
    87→              ...params,
    88→              resourceKey: params.resourceKey ?? resourceKey,
    89→              resourceType: "list",
    90→            }),
    91→        }
    92→      : {}),
    93→  } as ResourceKeys<T>;
    94→};
    95→

