     1→import { useMutation, useQueryClient } from "@tanstack/react-query";
     2→import { getApiClient } from "../../../../apiClientInstance";
     3→import type { Account } from "../../../../types/accounts";
     4→import type { ApiClientError } from "../../../../types/client";
     5→import { accountsOneQueryKeys } from "./queryKeys";
     6→
     7→type UsePauseAccountProps = {
     8→  onError?: (error: ApiClientError) => void;
     9→  onSuccess?: () => void;
    10→};
    11→
    12→type UsePauseAccountRequest = {
    13→  accountId: string;
    14→};
    15→
    16→export const usePauseAccount = ({
    17→  onError,
    18→  onSuccess,
    19→}: UsePauseAccountProps = {}) => {
    20→  const queryClient = useQueryClient();
    21→
    22→  return useMutation({
    23→    mutationFn: async ({ accountId }: UsePauseAccountRequest) => {
    24→      return getApiClient(true, "org").patch(`/accounts/${accountId}/pause`);
    25→    },
    26→    onError: (error: ApiClientError, variables, context) => {
    27→      // If the mutation fails, use the context returned from onMutate to roll back
    28→      if (context?.previousAccount) {
    29→        queryClient.setQueryData(
    30→          accountsOneQueryKeys.entity({ accountId: variables.accountId })
    31→            .queryKey,
    32→          context.previousAccount,
    33→        );
    34→      }
    35→      onError?.(error);
    36→    },
    37→    onMutate: async ({ accountId }: UsePauseAccountRequest) => {
    38→      // Cancel any outgoing refetches
    39→      await queryClient.cancelQueries({
    40→        queryKey: accountsOneQueryKeys.entity({ accountId }).queryKey,
    41→      });
    42→
    43→      // Snapshot the previous value
    44→      const previousAccount = queryClient.getQueryData<Account>(
    45→        accountsOneQueryKeys.entity({ accountId }).queryKey,
    46→      );
