#### 4. **Query Options Pattern**

All queries expose both `queryOptions` and hook wrappers:

```typescript
// hooks/org/donations/useGetDonation.ts
export const useGetDonationQueryOptions = (
  id: string,
  params: UseGetDonationParams,
  options?: Partial<UseGetOneOptions<Donation>>,
) => {
  return useGetOneQueryOptions(
    `/donations/${id}`,
    params,
    accountDonationsQueryKeys.entity({ parameters: params }).queryKey,
    { ...options },
  );
};

export const useGetDonation = (
  id: string,
  params: UseGetDonationParams,
  options?: Partial<UseGetOneOptions<Donation>>,
) => {
  return useQuery(useGetDonationQueryOptions(id, params, options));
};
```

**Key Points:**
- File naming: `use[ResourceName]QueryOptions` and `use[ResourceName]`
- Returns `queryOptions()` wrapped result for use in loaders
- Wraps with `useQuery()` for component usage
- Supports options extending `UseQueryOptions`

