├── accounts_/
│   └── $accountId/
│       ├── dashboard.tsx
│       ├── settings.tsx
│       └── settings/
│           ├── pause-account.tsx
│           ├── organization-info/
│           │   └── index.tsx
│           └── sms-keywords/
│               └── index.tsx
```

