#### 2. **Loader Function Pattern**

Loaders use `queryClient.ensureQueryData()` to prefetch data:

```typescript
export const Route = createFileRoute("/accounts_/$accountId/settings/pause-account")({
  component: RouteComponent,
  loader: async ({ params }) => {
    const { accountId } = params;

    await queryClient.ensureQueryData(
      useGetOneAccountQueryOptions({ accountId }),
    );

    return {
      accountId,
    };
  },
});
```

**Key Points:**
- Use `queryClient.ensureQueryData()` to prefetch queries
- Pass queryOptions directly (not hook call)
- Return data object for component access via `Route.useLoaderData()`
- Loaders run before route component renders

#### 3. **Multi-Query Loader Pattern**

Multiple queries prefetched with `Promise.all()`:

```typescript
export const Route = createFileRoute(
  "/accounts_/$accountId/settings/organization-info/",
)({
  component: RouteComponent,
  loader: async ({ params }) => {
    const { accountId } = params;

    await Promise.all([
      queryClient.ensureQueryData(useGetOneAccountQueryOptions({ accountId })),
      queryClient.ensureQueryData(
        useGetAccountConfigurationQueryOptions({ accountId }),
      ),
      queryClient.ensureQueryData(
        useGetAccountAddressesQueryOptions({
          accountId,
          addressTypes: ["legal", "physical", "mailing", "other"],
        }),
      ),
      queryClient.ensureQueryData(useGetMeQueryOptions({})),
    ]);

    return {
